using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator" вЂ” preserve old name for compatibility.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Existing documents have id format "Product|123" вЂ” preserve old format.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // EF Core 9: HasIndex now throws for Cosmos entities (was silently ignored).
        // Removed HasIndex вЂ” manage indexing policy via Azure Portal/Bicep/Terraform.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } = string.Empty; }

